code.C++:
long long stringToNumber(const string& str) {
    long long num = 0;
    for (char c : str) {
        num = num * 10 + (c - '0');
    }
    return num;
}

code.Python3:
def string_to_number(s):
    num = 0
    for char in s:
        num = num * 10 + (ord(char) - ord('0'))
    return num

code.C:
long long stringToNumber(const char* str) {
    long long num = 0;
    for (int i = 0; str[i] != '\0'; i++) {
        num = num * 10 + (str[i] - '0');
    }
    return num;
}

code.Java:
public static long stringToNumber(String str) {
    long num = 0;
    for (int i = 0; i < str.length(); i++) {
        num = num * 10 + (str.charAt(i) - '0');
    }
    return num;
}

